-- │                                                                    │
-- │  Iniciativa `dilesa-portafolio-predios` — S1b (carga de datos).    │
-- │  Importa los 2 Excel de prediales al portafolio:                   │
-- │    · PREDIALES DE PARCELAS EJ. VILLA DE FUENTE OK.xlsx             │
-- │      (parcelas ejidales + ranchos, histórico 2022-2026)            │
-- │    · DILESA PREDIALES 2026 actualizado revisado 01-07-26.xlsx      │
-- │      (predios urbanos por fraccionamiento, ejercicio 2026)         │
-- │                                                                    │
-- │  Idempotente (NOT EXISTS) y robusta a Preview (JOIN core.empresas: │
-- │  si la empresa no existe, no inserta nada). Generada por script    │
-- │  (parser con checksums contra las filas de totales del Excel).     │
-- │  Registro/control únicamente — no toca CxP ni mueve dinero.        │
-- ╰──────────────────────────────────────────────────────────────────╯

BEGIN;

-- 1. Convenio de reducción 60% (2026-2027) — acuerdo verbal documentado.
INSERT INTO dilesa.prediales_convenios (empresa_id, nombre, descuento_pct, ejercicio_desde, ejercicio_hasta, contraprestacion, estado)
SELECT e.id, 'Reducción predial 60% Piedras Negras 2026-2027', 60, 2026, 2027, 'Acuerdo verbal con el Municipio de Piedras Negras (2026): DILESA pagó el predial 2025 completo y entregará un área verde (terreno en trámite de relotificación) a cambio de una reducción del 60% del predial de los ejercicios 2026 y 2027. Registrado 2026-07-01; no existe documento firmado — este registro es el respaldo del acuerdo.', 'vigente'
FROM (SELECT id FROM core.empresas WHERE slug = 'dilesa') e
WHERE NOT EXISTS (
  SELECT 1 FROM dilesa.prediales_convenios c
  WHERE c.empresa_id = e.id AND c.nombre = 'Reducción predial 60% Piedras Negras 2026-2027'
);

-- 2. Activos (118: parcelas/ranchos tipo terreno + lotes comerciales urbanos).
INSERT INTO dilesa.activos
  (empresa_id, tipo, nombre, estado, zona, municipio, estado_geo, area_m2, situacion_legal, clave_catastral, clave_interna, destino_id, notas)
SELECT e.id, v.tipo, v.nombre, v.estado, v.zona, v.municipio, 'Coahuila', v.area_m2, v.situacion_legal, v.clave_catastral, v.clave_interna,
       (SELECT d.id FROM dilesa.portafolio_destinos d WHERE d.empresa_id = e.id AND d.slug = v.destino_slug),
       v.notas
FROM (SELECT id FROM core.empresas WHERE slug = 'dilesa') e
CROSS JOIN (VALUES
