-- 4. Ejercicios (186: histórico 2022-2026 de parcelas + 2026 urbano).
--    Los urbanos 2026 con adeudo quedan estado='convenio' ligados a la
--    reducción 60%; el adeudo neto se deriva en la UI (montos intactos).
INSERT INTO dilesa.prediales_ejercicios
  (empresa_id, cuenta_id, ejercicio, predial, recargos, aseo, recargos_aseo, bomberos, recargos_bomberos, estado, convenio_id, notas)
